import{_ as t,H as a,f as o,i}from"./chunks/framework.Cvt1eIE0.js";const u=JSON.parse('{"title":"FewUI Kit","description":"","frontmatter":{},"headers":[],"relativePath":"kit/index.md","filePath":"kit/index.md"}'),s={name:"kit/index.md"};function r(n,e,l,d,c,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="fewui-kit" tabindex="-1">FewUI Kit <a class="header-anchor" href="#fewui-kit" aria-label="Permalink to &quot;FewUI Kit&quot;">​</a></h1><p>FewUI is not only a Vue component library. It is an <strong>AI-native design system</strong>: components, design tokens, Cursor rules, and agent skills share one contract so humans and AI assistants build UIs with the same vocabulary.</p><h2 id="what-kit-includes" tabindex="-1">What Kit includes <a class="header-anchor" href="#what-kit-includes" aria-label="Permalink to &quot;What Kit includes&quot;">​</a></h2><ul><li><strong><code>ui-*</code> components</strong> — forms, dialogs, tables, navigation, and more.</li><li><strong><code>UiThemeConfig</code></strong> — runtime theming via CSS custom properties (<code>applyUiTheme</code>, <code>mergeUiTheme</code>).</li><li><strong>Presets</strong> — <code>panel</code> (admin), <code>flat</code> (solid surfaces), <code>landing</code> (tenant sites).</li><li><strong>Playground</strong> — live component gallery with a theme sidebar (<a href="http://localhost:5175" target="_blank" rel="noreferrer">localhost:5175</a>).</li><li><strong>Rules &amp; skills</strong> — exportable Cursor rules and <code>SKILL.md</code> for agent workflows.</li></ul><h2 id="ai-first-philosophy" tabindex="-1">AI-first philosophy <a class="header-anchor" href="#ai-first-philosophy" aria-label="Permalink to &quot;AI-first philosophy&quot;">​</a></h2><p>Traditional UI kits document props for humans. FewUI also documents <strong>decisions</strong>:</p><ul><li>Which component to use for a pattern (never raw <code>&lt;button&gt;</code> for primary actions).</li><li>How errors surface (<code>ui-alert</code>, API message helpers).</li><li>How theming flows from a single <code>primaryColor</code> to accents and SSR.</li></ul><p>Restta (restaurant POS, web module, landing) is the reference production app built on Kit.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="./getting-started.html">Getting started</a></li><li><a href="./theming.html">Theming</a></li><li><a href="./skills-and-rules.html">Skills &amp; rules</a></li></ul>',10)])])}const m=t(s,[["render",r]]);export{u as __pageData,m as default};
